<template><view class="page"><view class="intro"><text class="eyebrow">BRAND VISUAL</text><text class="title">品牌视觉任务</text><text class="desc">为已保存的候选名创建 Logo、品牌板或名片任务。</text></view><view v-if="context.record_id" class="form"><text class="selected">{{context.name}}</text><picker :range="typeLabels" @change="typeIndex=Number($event.detail.value)"><view class="picker">{{typeLabels[typeIndex]}}⌄</view></picker><textarea v-model="prompt" maxlength="500" placeholder="补充色彩、风格、图形偏好（可选）"/><button :loading="creating" @click="create">创建视觉任务</button></view><view v-else class="empty">请先从首页候选名字进入品牌视觉。</view><view class="section-head"><text>我的视觉任务</text><text @click="load">刷新</text></view><view v-if="!items.length" class="empty">暂无视觉任务</view><view v-for="item in items" :key="item.id" class="visual"><image v-if="item.image_url" :src="item.image_url" mode="aspectFill"/><view v-else class="placeholder">{{String(item.candidate_name||'视觉').slice(0,2)}}</view><view class="info"><view class="row"><text class="name">{{item.candidate_name}}</text><text :class="['status',item.status]">{{statusText(item.status)}}</text></view><text class="meta">{{typeText(item.task_type)}} · {{formatDate(item.created_at)}}</text><text v-if="item.error_message" class="error">{{item.error_message}}</text><view class="actions"><text v-if="item.status==='failed'" @click="retry(item)">重试</text><text @click="remove(item)">删除</text></view></view></view></view></template>
<script setup>import{ref}from'vue';import{onPullDownRefresh,onShow}from'@dcloudio/uni-app';import http from'@/http/http.js';const types=['logo','brand_board','business_card'],typeLabels=['Logo 概念','品牌视觉板','名片排版'];const typeIndex=ref(0),prompt=ref(''),items=ref([]),context=ref({}),creating=ref(false);const load=async()=>{const r=await http.getVisualTasks({page:1,page_size:50});items.value=r.items||[];uni.stopPullDownRefresh();};onShow(()=>{context.value=uni.getStorageSync('selectedCandidate')||{};load();});onPullDownRefresh(load);const create=async()=>{creating.value=true;try{await http.createVisualTask({record_id:Number(context.value.record_id),candidate_id:context.value.candidate_id?Number(context.value.candidate_id):null,task_type:types[typeIndex.value],prompt:prompt.value.trim()||null,provider:'mock'});prompt.value='';await load();uni.showToast({title:'视觉任务已创建',icon:'success'});}finally{creating.value=false;}};const retry=async i=>{await http.retryVisualTask(i.id);await load();};const remove=i=>uni.showModal({title:'删除视觉任务',content:'删除后不可恢复，是否继续？',success:async({confirm})=>{if(confirm){await http.deleteVisualTask(i.id);await load();}}});const statusText=v=>({pending:'排队中',processing:'生成中',completed:'已完成',failed:'失败'}[v]||v);const typeText=v=>({logo:'Logo',brand_board:'品牌板',business_card:'名片'}[v]||v);const formatDate=v=>String(v||'').replace('T',' ').slice(0,16);</script>
<style scoped>.page{min-height:100vh;padding:34rpx 30rpx 90rpx;box-sizing:border-box;background:#f7f4ee;color:#292620}.eyebrow,.title,.desc,.selected,.meta,.error{display:block}.eyebrow{color:#8b6e40;font-size:17rpx;letter-spacing:4rpx}.title{margin-top:9rpx;font-family:serif;font-size:42rpx;font-weight:700}.desc{margin-top:10rpx;color:#938a7e;font-size:21rpx}.form,.visual,.empty{margin-top:22rpx;padding:25rpx;border-radius:20rpx;background:#fff}.selected{font-size:30rpx;font-weight:700}.picker,.form textarea{margin-top:16rpx;padding:0 20rpx;border-radius:12rpx;background:#f6f3ed}.picker{height:75rpx;line-height:75rpx}.form textarea{width:100%;height:150rpx;padding-top:18rpx;box-sizing:border-box}.form button{margin-top:18rpx;color:#fff;background:#3e5a4d}.section-head,.row{display:flex;justify-content:space-between}.section-head{margin:36rpx 4rpx 8rpx;font-size:28rpx;font-weight:700}.section-head text:last-child{color:#547061;font-size:20rpx}.empty{text-align:center;color:#968d82}.visual{display:flex;gap:18rpx}.visual image,.placeholder{width:125rpx;height:125rpx;flex-shrink:0;border-radius:16rpx}.placeholder{display:flex;align-items:center;justify-content:center;color:#fff;background:linear-gradient(135deg,#395449,#9a7952);font-size:32rpx;font-weight:700}.info{flex:1}.name{font-size:26rpx;font-weight:700}.status{font-size:18rpx;color:#8c8377}.status.completed{color:#347050}.status.failed,.error{color:#a64e44}.meta{margin-top:9rpx;color:#978e82;font-size:18rpx}.actions{margin-top:17rpx;text-align:right}.actions text{margin-left:22rpx;color:#557263;font-size:20rpx}</style>
